import{_ as t,o as a,c as r,a0 as o}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"Kingshot Event Tracker — User Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"README.md","filePath":"README.md"}'),n={name:"README.md"};function i(s,e,l,h,d,g){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="kingshot-event-tracker-—-user-documentation" tabindex="-1">Kingshot Event Tracker — User Documentation <a class="header-anchor" href="#kingshot-event-tracker-—-user-documentation" aria-label="Permalink to &quot;Kingshot Event Tracker — User Documentation&quot;">​</a></h1><p>Welcome! The Kingshot Event Tracker is a web app that helps kingdoms and alliances keep score of in‑game events, track their players, and see who earned rewards. This documentation is written for the people who <em>use</em> the app — no technical or coding knowledge is assumed.</p><p>If you are brand new, start with <strong><a href="./getting-started/what-is-the-tracker.html">What the Tracker Does</a></strong> and keep the <strong><a href="./getting-started/glossary.html">Glossary</a></strong> open in another tab. The glossary defines every term (template, instance, review row, grant, effective plan, and so on) that the rest of the docs rely on.</p><h2 id="start-here" tabindex="-1">Start here <a class="header-anchor" href="#start-here" aria-label="Permalink to &quot;Start here&quot;">​</a></h2><ol><li><a href="./getting-started/what-is-the-tracker.html">What the Tracker Does</a> — the big picture in five minutes.</li><li><a href="./getting-started/glossary.html">Glossary</a> — every key term, plainly defined.</li><li><a href="./getting-started/logging-in.html">Log In &amp; Out</a> — getting into the app.</li><li><a href="./getting-started/navigating.html">Finding Your Way Around</a> — the sidebar, the top bar, and where things live.</li><li><a href="./getting-started/dashboard-tour.html">Reading the Dashboard</a> — what the home screen is showing you.</li></ol><h2 id="find-your-guide-by-role" tabindex="-1">Find your guide by role <a class="header-anchor" href="#find-your-guide-by-role" aria-label="Permalink to &quot;Find your guide by role&quot;">​</a></h2><p>Everyone in the app has a <strong>role</strong> that decides what they can see and do. If you are not sure which role you have, look at the top of any page — your role is shown in the context banner. See <strong><a href="./roles/overview.html">Roles Explained</a></strong> for the full picture.</p><table tabindex="0"><thead><tr><th>Your role</th><th>Start with</th></tr></thead><tbody><tr><td><strong>Alliance Player</strong> (view‑only member)</td><td><a href="./roles/overview.html">Roles Explained</a> → <a href="./getting-started/dashboard-tour.html">Reading the Dashboard</a></td></tr><tr><td><strong>Co‑Leader</strong> (helps track and enter data)</td><td><a href="./roles/overview.html">Roles Explained</a> → <a href="./getting-started/navigating.html">Finding Your Way Around</a></td></tr><tr><td><strong>Alliance Leader</strong> (runs one alliance)</td><td><a href="./roles/overview.html">Roles Explained</a> → <em>My Alliance guide (coming in a later section)</em></td></tr><tr><td><strong>King</strong> (runs one kingdom)</td><td><a href="./roles/overview.html">Roles Explained</a> → <a href="./roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a></td></tr><tr><td><strong>Supreme Admin</strong> (runs the whole platform)</td><td><a href="./roles/overview.html">Roles Explained</a> → <a href="./roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a></td></tr></tbody></table><h2 id="account-sign‐in-help" tabindex="-1">Account &amp; sign‑in help <a class="header-anchor" href="#account-sign‐in-help" aria-label="Permalink to &quot;Account &amp; sign‑in help&quot;">​</a></h2><ul><li><a href="./getting-started/registering.html">Request an Account</a></li><li><a href="./getting-started/forgot-password.html">Reset a Forgotten Password</a></li><li><a href="./getting-started/your-profile.html">Edit Your Profile &amp; Password</a></li><li><a href="./getting-started/access-denied.html">&quot;You don&#39;t have access&quot; — What It Means</a></li></ul><h2 id="good-to-know-before-you-worry" tabindex="-1">Good to know before you worry <a class="header-anchor" href="#good-to-know-before-you-worry" aria-label="Permalink to &quot;Good to know before you worry&quot;">​</a></h2><ul><li><a href="./roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a> — the guardrails that stop you (or someone else) from locking the platform or deleting the wrong thing.</li><li><a href="./reference/soft-delete.html">What &quot;Delete&quot; Really Does</a> — deleting almost never means &quot;gone forever.&quot; Read this before you panic about missing data.</li></ul><hr><p><em>This is the first published section of the documentation (getting started, roles, and core concepts). More sections — players, events, imports, subscriptions, and admin guides — are being added.</em></p>',14)])])}const m=t(n,[["render",i]]);export{c as __pageData,m as default};
